uint32_t read_uint32_from_file(const std::filesystem::path& file_path) {
    // Create a hexi::file_buffer object with the given file path
    hexi::file_buffer buffer(file_path);

    // Check if the file buffer is in a valid state
    if (!buffer) {
        return 0; // Return default value on error
    }

    // Use the template read method to read a uint32_t value
    uint32_t value;
    buffer.read(&value);

    // Check for read errors
    if (buffer.error()) {
        return 0; // Return default value on read error
    }

    return value;
}

void write_uint32_to_file(const std::filesystem::path& file_path, uint32_t value) {
    // Create a hexi::file_buffer object with the given file path
    hexi::file_buffer buffer(file_path);

    // Check if the file buffer is in a valid state
    if (!buffer) {
        return; // Exit on error
    }

    // Use the template write method to write the uint32_t value
    buffer.write(value);

    // Flush to ensure data is written to disk
    buffer.flush();
}
