#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/shared.h>
#include <vector>
#include <cstdint>

bool check_can_write_seek(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    // Use the can_write_seek() method to check if the buffer supports write seeking
    return buffer.can_write_seek();
}

void seek_write_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, hexi::buffer_seek direction, std::size_t offset) {
    // Use the write_seek() method with the given direction and offset to move the write position
    buffer.write_seek(direction, offset);
}

void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t header_value) {
    // Save the current write position using tell_write()
    auto current_pos = buffer.tell_write();

    // Use write_seek() with sk_absolute to set position to 0 (beginning)
    buffer.write_seek(hexi::buffer_seek::sk_absolute, 0);

    // Write the header (uint32_t) at the beginning
    buffer.write(&header_value, sizeof(header_value));

    // Write some body data (example: a simple string)
    const char* body_data = "Hello, World!";
    buffer.write(body_data, strlen(body_data));

    // Use write_seek() with sk_absolute to return to position 0
    buffer.write_seek(hexi::buffer_seek::sk_absolute, 0);

    // Update the header with new information (example: increment the header value)
    uint32_t updated_header = header_value + 1;
    buffer.write(&updated_header, sizeof(updated_header));

    // Restore the original write position using the saved position
    buffer.write_seek(hexi::buffer_seek::sk_absolute, current_pos);
}
